   242→	s.log.Debug("Plugin signature valid", "id", plugin.JSONData.ID)
   243→	return plugins.Signature{
   244→		Status:     plugins.SignatureStatusValid,
   245→		Type:       manifest.SignatureType,
   246→		SigningOrg: manifest.SignedByOrgName,
   247→	}, nil
   248→}
