   173→// ReportCloudProvisioningMetrics reports plugin cloud provisioning information for all non-core plugins.
   174→func ReportCloudProvisioningMetrics(ppManaged provisionedplugins.Manager) initialization.InitializeFunc {
   175→	cloudProvisioningMethod := plugins.CloudProvisioningMethodNone
   176→	pps, err := ppManaged.ProvisionedPlugins(context.Background())
   177→	if err != nil {
   178→		cloudProvisioningMethod = plugins.CloudProvisioningMethodUnknown
   179→		logger.Warn("Failed to get provisioned plugins", "error", err)
   180→	}
   181→
   182→	return func(ctx context.Context, p *plugins.Plugin) (*plugins.Plugin, error) {
   183→		if p.IsCorePlugin() {
   184→			// No metrics for core plugins
   185→			return p, nil
   186→		}
   187→
   188→		for _, pp := range pps {
   189→			if pp.ID != p.ID {
   190→				continue
   191→			}
   192→			if pp.URL == "" {
   193→				cloudProvisioningMethod = plugins.CloudProvisioningMethodCatalog
   194→			} else {
   195→				cloudProvisioningMethod = plugins.CloudProvisioningMethodURL
   196→			}
   197→			metrics.SetPluginProvisioningInformation(p.ID, string(cloudProvisioningMethod))
