   250→// Filter will filter out any plugins that are marked to be disabled.
   251→func (c *DisablePlugins) Filter(bundles []*plugins.FoundBundle) ([]*plugins.FoundBundle, error) {
   252→	if len(c.cfg.DisablePlugins) == 0 {
   253→		return bundles, nil
   254→	}
   255→
   256→	disablePluginsMap := make(map[string]bool)
   257→	for _, pluginID := range c.cfg.DisablePlugins {
   258→		disablePluginsMap[pluginID] = true
   259→	}
   260→
   261→	res := []*plugins.FoundBundle{}
   262→	for _, bundle := range bundles {
   263→		if disablePluginsMap[bundle.Primary.JSONData.ID] {
   264→			c.log.Debug("Disabling plugin load", "pluginID", bundle.Primary.JSONData.ID)
   265→		} else {
   266→			res = append(res, bundle)
   267→		}
   268→	}
   269→	return res, nil
   270→}
