   113→// readPluginAPIRestrictionsSection reads a plugin API restrictions section and returns a map of API names to plugin lists
   114→func readPluginAPIRestrictionsSection(iniFile *ini.File, sectionName string) map[string][]string {
   115→	result := make(map[string][]string)
   116→
   117→	if !iniFile.HasSection(sectionName) {
   118→		return result
   119→	}
   120→
   121→	section := iniFile.Section(sectionName)
   122→	for _, key := range section.Keys() {
   123→		apiName := key.Name()
   124→		pluginList := util.SplitString(key.MustString(""))
   125→		if len(pluginList) > 0 {
   126→			result[apiName] = pluginList
   127→		}
   128→	}
   129→
   130→	return result
   131→}
